import { useEffect, useRef } from "react";
import { useLocation } from "react-router-dom";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { generateUUID } from "@/lib/uuid";
import { isAnalyticsAllowed, isEssentialAllowed, anonymizeIp } from "@/lib/cookieConsent";

const VISITOR_KEY = "visitor_id";
const LOCATION_CACHE_KEY = "location_cache";

const getVisitorId = (): string => {
  let id = localStorage.getItem(VISITOR_KEY);
  if (!id) {
    id = generateUUID();
    localStorage.setItem(VISITOR_KEY, id);
  }
  return id;
};

const getCachedLocation = () => {
  try {
    const c = sessionStorage.getItem(LOCATION_CACHE_KEY);
    return c ? JSON.parse(c) : null;
  } catch {
    return null;
  }
};

// Hostnames that should NOT be tracked (dev/preview environments)
const DEV_HOSTNAMES = ["lovableproject.com", "lovable.app", "localhost", "127.0.0.1"];

const isDevEnvironment = (): boolean => {
  const h = window.location.hostname;
  if (h === "xiaoxiongmarket.com" || h === "www.xiaoxiongmarket.com") return false;
  return DEV_HOSTNAMES.some((d) => h.includes(d));
};

interface LogVisitInput {
  path: string;
  search?: string;
  status?: "ok" | "404" | "error";
  status_code?: number;
  error_message?: string;
  duration_ms?: number;
}

const ENABLE_DEV_TRACKING = false;

export const logVisit = async (params: LogVisitInput, user?: { id?: string; email?: string | null }) => {
  if (isDevEnvironment() && !ENABLE_DEV_TRACKING) return;

  const status = params.status || "ok";
  const isError = status === "error" || status === "404";

  // Consent gate: errors/404 = essential (always allowed once banner shown);
  // 'ok' route tracking requires explicit analytics consent.
  if (!isError && !isAnalyticsAllowed()) return;
  if (isError && !isEssentialAllowed()) return;

  const analyticsOk = isAnalyticsAllowed();

  try {
    const loc = getCachedLocation();
    await supabase.from("visit_logs" as any).insert({
      visitor_id: getVisitorId(),
      user_id: user?.id || null,
      user_email: user?.email || null,
      path: params.path,
      // Strip query params if user only granted essential (may contain PII)
      search: analyticsOk ? params.search || null : null,
      status,
      status_code: params.status_code ?? null,
      error_message: params.error_message ?? null,
      referer: analyticsOk ? document.referrer || null : null,
      user_agent: navigator.userAgent,
      country: analyticsOk ? loc?.country || null : null,
      city: analyticsOk ? loc?.city || null : null,
      // Always anonymize IP (GDPR best practice)
      ip: anonymizeIp(loc?.ip),
      duration_ms: analyticsOk ? params.duration_ms ?? null : null,
    });
  } catch (e) {
    // Silent — never break the app
    console.warn("[VisitTracker] log failed:", e);
  }
};

/**
 * Tracks every route change. Records:
 *  - path/search
 *  - duration on previous page
 *  - associated user (if logged in)
 */
export const useVisitTracker = () => {
  const location = useLocation();
  const { user } = useAuth();
  const enterTime = useRef<number>(Date.now());
  const lastPath = useRef<string>("");

  useEffect(() => {
    const fullPath = location.pathname;
    const search = location.search;

    // Compute duration on previous page
    const now = Date.now();
    const duration = lastPath.current ? now - enterTime.current : undefined;

    // If we tracked a previous page, update it with duration (best-effort: log a synthetic event)
    // Simpler approach: log this new page and record the duration on it via beforeunload.
    enterTime.current = now;
    lastPath.current = fullPath;

    logVisit(
      {
        path: fullPath,
        search: search || undefined,
        status: "ok",
        duration_ms: duration,
      },
      { id: user?.id, email: user?.email }
    );
  }, [location.pathname, location.search, user?.id, user?.email]);
};

export default useVisitTracker;
